<w:p wsp:rsidR="003416D7" wsp:rsidRPr="00F52CF4" wsp:rsidRDefault="003416D7" wsp:rsidP="003416D7"><w:pPr><w:shd w:val="clear" w:color="auto" w:fill="FFFFFF"/><w:rPr><w:b/><w:sz w:val="22"/><w:sz-cs w:val="22"/></w:rPr></w:pPr><w:r wsp:rsidRPr="00F52CF4"><w:rPr><w:b/><w:sz w:val="18"/><w:sz-cs w:val="22"/></w:rPr><w:t>ВЪРНЕТЕ ТОЗИ ЕКЗЕМПЛЯР НА СЪДЕБНИЯ ИЗПЪЛНИТЕЛ ВЕДНАГА СЛЕД СЪСТАВЯНЕТО МУ!</w:t></w:r></w:p>
